#include <bits/stdc++.h>
using namespace std;
const int N=1e6+6;
struct Edge{
	int to,val;
};
int n,siz[N],deep[N];
vector<Edge> g[N];
long long solve(int x){
	siz[x]=1;
	int len=g[x].size();
	long long ans=0;
	for(int i=0;i<len;i++)
		if(!siz[g[x][i].to]){
			deep[g[x][i].to]=deep[x]+1;
			ans+=solve(g[x][i].to);
			siz[x]+=siz[g[x][i].to];
		}
	for(int i=0;i<len;i++)
		if(deep[g[x][i].to]>deep[x])
			ans+=1LL*g[x][i].val*abs(siz[g[x][i].to]-(n-siz[g[x][i].to]));
	return ans;
}
int main(){
	scanf("%d",&n);
	for(int i=1;i<n;i++){
		int a,b,c;
		scanf("%d%d%d",&a,&b,&c);
		g[a].push_back({b,c});
		g[b].push_back({a,c});
	}
	deep[1]=1;
	printf("%lld",solve(1));
	return 0;
}
